<script setup>
import { ref } from 'vue'
import { getBaseStatisticsInfo, getArticlePVStatisticsInfo, getUpdateCount } from '@/api/admin/dashboard'
import { getOsCount, getDeviceCount, getPageCount, getBrowserCount, getPeriodCount } from '@/api/admin/userStats'
import ArticlePVLineChat from '@/components/ArticlePVLineChat.vue'
import OsCountChat from '@/components/OsCountChat.vue'
import DeviceCountChat from '@/components/DeviceCountChat.vue'
import FrontBackChat from '@/components/FrontBackChat.vue'
import BrowserCountChat from '@/components/BrowserCountChat.vue'
import PeriodCountChat from '@/components/PeriodCountChat.vue'


// 文章总数，默认值为 0
const articleTotalCount = ref(0)
// 分类总数
const categoryTotalCount = ref(0)
// 标签总数
const tagTotalCount = ref(0)
// PV 总访问量
const pvTotalCount = ref(0)

getBaseStatisticsInfo().then(res => {
    if (res.success) {
        articleTotalCount.value = res.data.articleTotalCount
        categoryTotalCount.value = res.data.categoryTotalCount
        tagTotalCount.value = res.data.tagTotalCount
        pvTotalCount.value = res.data.pvTotalCount
    }
})



// 近一周文章 PV 数据 默认为对象
const articlePVInfo = ref({})
// 更新次数数据 默认为对象
const updateCount = ref({})

getArticlePVStatisticsInfo().then((res) => {
    if (res.success) {
        articlePVInfo.value = res.data
    }
})

getUpdateCount().then((res) => {
    if (res.success) {
        updateCount.value = res.data
    }
})

const osCountInfoOfMobile = ref({})

const osCountInfoOfDesk = ref({})

getOsCount('移动端').then((res) => {
    if (res.success) {
        osCountInfoOfMobile.value = res.data
    }
})
getOsCount('桌面端').then((res) => {
    if (res.success) {
        osCountInfoOfDesk.value = res.data
    }
})


const deviceCountInfo = ref([])
getDeviceCount().then((res) => {
    if (res.success) {
        deviceCountInfo.value = res.data
    }
})


const pageCountInfo = ref([])
getPageCount().then((res) => {
    if (res.success) {
        pageCountInfo.value = res.data
    }
})

const browserCountInfo = ref({})
getBrowserCount().then((res) => {
    if (res.success) {
        browserCountInfo.value = res.data
    }
})

const periodCountInfo = ref({})
getPeriodCount().then((res) => {
    if(res.success){
        periodCountInfo.value = res.data
    }
})

</script>

